package edu.rice.comp322;

import edu.rice.hj.api.SuspendableException;

/**
 * Any method of scoring the sequential alignment of two DNA strings.
 *
 * @author Derek
 */
public abstract class AbstractDnaScoring {

    // scoring matrix
    /*
           _  A  C  G  T
        ------------------
        _ |-8 -2 -2 -2 -2
        A |-4  5  2  2  2
        C |-4  2  5  2  2
        G |-4  2  2  5  2
        T |-4  2  2  2  5
    */
    protected static final int[][] M = new int[][]{{-8, -2, -2, -2, -2},
        {-4, 5, 2, 2, 2},
        {-4, 2, 5, 2, 2},
        {-4, 2, 2, 5, 2},
        {-4, 2, 2, 2, 5}};

    /**
     * Helper method for getting the index of character in scoring matrix.
     *
     * @param inputChar The character to search for.
     * @return The index of the requested character in the matrix.
     */
    protected int charMap(final char inputChar) {
        switch (inputChar) {
            case '_':
                return 0;
            case 'A':
            case 'a':
                return 1;
            case 'C':
            case 'c':
                return 2;
            case 'G':
            case 'g':
                return 3;
            case 'T':
            case 't':
                return 4;
            default:
                throw new IllegalArgumentException("Invalid DNA character: " + inputChar);
        }
    }

    /**
     * Get score assigned for alignment of two letters.
     *
     * @param iVal the first index in the scoring matrix
     * @param jVal the second index in the scoring matrix
     * @return the corresponding value in the matrix
     */
    protected int getScore(final int iVal, final int jVal) {
        return M[iVal][jVal];
    }

    /**
     * Helper method for printing out a two dimensional int array, can be useful for debugging.
     *
     * @param matrix The desired int matrix to be printed.
     */
    public void printMatrix(final int[][] matrix) {
        for (int i = 0; i < matrix.length; i++) {
            for (int j = 0; j < matrix[0].length; j++) {
                System.out.print(matrix[i][j] + " ");
            }
            System.out.println();
        }
        System.out.println("--------------------------------");
    }

    /**
     * Compute the solution matrix and return the alignment score of two DNA sequences. This one is done sequentially.
     *
     * @param x The first sequence to be compared.
     * @param y The second sequence to be compared.
     * @return The alignment score between them
     */
    public abstract int scoreSequences(String x, String y) throws SuspendableException;
}

package edu.rice.comp322;

import edu.rice.hj.api.SuspendableException;

/**
 * Sequential Smith-Waterman algorithm adapted for COMP 322 homework.
 */
public class TestSeqScoring extends AbstractPreallocatedSorting {

    /**
     * Creates a new TestSeqScoring.
     *
     * @param xLength length of the first sequence
     * @param yLength length of the second sequence
     */
    public TestSeqScoring(final int xLength, final int yLength) {
        super(xLength, yLength);
    }

    /**
     * A reference sequential implementation of the Smith-Waterman alignment algorithm.
     * {@inheritDoc}
     */
    public int scoreSequences(final String x, final String y) throws SuspendableException {

        final int xLength = getXLength();
        final int yLength = getYLength();
        final int[][] S = getMatrix();

        for (int i = 1; i <= xLength; i++) {
            for (int j = 1; j <= yLength; j++) {
                // the two characters to be compared
                final char XChar = x.charAt(i - 1);
                final char YChar = y.charAt(j - 1);

                // find the largest point to jump from, and use it
                final int diagScore = S[i - 1][j - 1] + getScore(charMap(XChar), charMap(YChar));
                final int topColScore = S[i - 1][j] + getScore(charMap(XChar), 0);
                final int leftRowScore = S[i][j - 1] + getScore(0, charMap(YChar));
                S[i][j] = Math.max(diagScore, Math.max(leftRowScore, topColScore));
            }
        }

        // final value in the matrix is the score
        return S[xLength][yLength];
    }

}

package edu.rice.comp322;

import java.io.BufferedReader;
import java.io.FileReader;
import java.io.IOException;

import static edu.rice.hj.Module0.launchHabaneroApp;

/**
 * Contains all of the code necessary to test a DNA scorer through multiple trials.
 */
public class ScoringRunner {

    /**
     * The constructor of a DNA scoring.
     */
    private final IScoringConstructor constructor;

    /**
     * Creates a runner.
     *
     * @param constructor provides the DNA scoring to run
     */
    public ScoringRunner(final IScoringConstructor constructor) {
        this.constructor = constructor;
    }

    /**
     * Starts the runner.
     *
     * @param mainName the name of the class that called this method
     * @param args     the arguments that class was given, should be the names of two files
     * @throws java.io.IOException on a file name or system problem
     */
    public void start(final String mainName, final String[] args) throws IOException {

        // first read the two files as DNA sequences

        final String filename1;
        final String filename2;

        if (args.length == 2) {
            filename1 = args[0];
            filename2 = args[1];
            System.out.println("File Name-1: " + filename1);
            System.out.println("File Name-2: " + filename2);
        } else {
            System.out.println("Usage: ./" + mainName + " fileName1 fileName2");
            return;
        }

        final String X = initString(filename1);
        final String Y = initString(filename2);
        System.out.println("Size of input string 1 is " + X.length());
        System.out.println("Size of input string 2 is " + Y.length());

        // then test scorers created by the given constructor against the two sequences

        final int xLength = X.length();
        final int yLength = Y.length();
        final int numIter = 5;
        final long[] times = new long[numIter];
        final int[] scores = new int[numIter];
        long totalTime = 0;
        long minTime = Long.MAX_VALUE;


        for (int iter = 0; iter < numIter; iter++) {

            final int iterLoc = iter;
            final long[] execTime = {0};
            launchHabaneroApp(() -> {
                final AbstractDnaScoring scoring = constructor.create(xLength, yLength);
                final long start = System.currentTimeMillis();

                final int score = scoring.scoreSequences(X, Y);
                scores[iterLoc] = score;

                execTime[0] = System.currentTimeMillis() - start;
                System.out.println("  The score = " + score + " in iteration " + (iterLoc + 1));
                System.out.println("  The execution time = " + execTime[0] + " milliseconds in iteration " + (iterLoc + 1));
            });
            totalTime += execTime[0];
            times[iter] = execTime[0];
            if (execTime[0] < minTime) {
                minTime = execTime[0];
            }

        }
        for (int iter = 1; iter < numIter; iter++) {
            if (scores[iter] != scores[0]) {
                System.err.println("Different scores from different runs! " + scores[iter] + " and " + scores[0]);
            }
        }
        System.out.println("Avg time of computation is " + totalTime / numIter);
        System.out.println("Min time of computation is " + minTime + " milliseconds ");
    }

    /**
     * Read the sequence from a given text file.
     *
     * @param fileName The file name to read text from.
     * @return A string containing the sequence from the file.
     * @throws java.io.IOException if any.
     */
    private String initString(final String fileName) throws IOException {
        final BufferedReader r = new BufferedReader(new FileReader(fileName));
        final StringBuilder text = new StringBuilder();
        String line;
        while ((line = r.readLine()) != null) {
            text.append(line);
        }
        return text.toString();
    }
}

