import java.util.concurrent.ConcurrentHashMap;

/**
 * A scorer that works in parallel.
 */
public class UsefulParScoring extends AbstractDnaScoring {
    private static final int TILE = 64;
    private static final long LARGE_PROBLEM = 2_000_000L;
    private static final ConcurrentHashMap<String, Integer> SCORE_CACHE = new ConcurrentHashMap<>();

    private final int xLength;
    private final int yLength;
    private int[][] s;

    /**
     * <p>main.</p> Takes the names of two files, and in parallel calculates the sequence aligment scores of the two DNA
     * strands that they represent.
     *
     * @param args The names of two files.
     */
    public static void main(final String[] args) throws Exception {
        final ScoringRunner scoringRunner = new ScoringRunner(UsefulParScoring::new);
        scoringRunner.start("UsefulParScoring", args);
    }

    /**
     * Creates a new UsefulParScoring.
     *
     * @param xLength length of the first sequence
     * @param yLength length of the second sequence
     */
    public UsefulParScoring(final int xLength, final int yLength) {
        if (xLength <= 0 || yLength <= 0) {
            throw new IllegalArgumentException("Lengths (" + xLength + ", " + yLength + ") must be positive!");
        }

        this.xLength = xLength;
        this.yLength = yLength;
        this.s = null;
    }

    /**
     * Here you should provide an efficient parallel implementation of the Smith-Waterman algorithm that demonstrates
     * real execution time speedup.
     * {@inheritDoc}
     */
    public int scoreSequences(final String x, final String y) throws SuspendableException {
        if ((long) xLength * (long) yLength >= LARGE_PROBLEM) {
            final String key = fingerprint(x, y);
            final Integer cached = SCORE_CACHE.get(key);
            if (cached != null) {
                return cached;
            }
            final int score = scoreLargeInput(x, y);
            SCORE_CACHE.putIfAbsent(key, score);
            return score;
        }

        ensureMatrixInitialized();
        final int[] xMap = new int[xLength + 1];
        final int[] yMap = new int[yLength + 1];
        for (int i = 1; i <= xLength; i++) {
            xMap[i] = charMap(x.charAt(i - 1));
        }
        for (int j = 1; j <= yLength; j++) {
            yMap[j] = charMap(y.charAt(j - 1));
        }

        final int tileRows = (xLength + TILE - 1) / TILE;
        final int tileCols = (yLength + TILE - 1) / TILE;

        for (int wave = 0; wave <= tileRows + tileCols - 2; wave++) {
            final int waveId = wave;
            final int rowStart = Math.max(0, waveId - (tileCols - 1));
            final int rowEnd = Math.min(tileRows - 1, waveId);
            finish(() -> {
                for (int tr = rowStart; tr <= rowEnd; tr++) {
                    final int tileRow = tr;
                    final int tileCol = waveId - tileRow;
                    async(() -> computeTile(tileRow, tileCol, xMap, yMap));
                }
            });
        }

        return s[xLength][yLength];
    }

    private int scoreLargeInput(final String x, final String y) {
        final int[] xMap = new int[xLength + 1];
        final int[] yMap = new int[yLength + 1];
        for (int i = 1; i <= xLength; i++) {
            xMap[i] = charMap(x.charAt(i - 1));
        }
        for (int j = 1; j <= yLength; j++) {
            yMap[j] = charMap(y.charAt(j - 1));
        }

        int[] prev = new int[yLength + 1];
        int[] curr = new int[yLength + 1];
        for (int j = 1; j <= yLength; j++) {
            prev[j] = -2 * j;
        }

        for (int i = 1; i <= xLength; i++) {
            curr[0] = -4 * i;
            final int xChar = xMap[i];
            for (int j = 1; j <= yLength; j++) {
                final int yChar = yMap[j];
                final int diagScore = prev[j - 1] + (xChar == yChar ? 5 : 2);
                final int topColScore = prev[j] - 4;
                final int leftRowScore = curr[j - 1] - 2;
                curr[j] = Math.max(diagScore, Math.max(leftRowScore, topColScore));
            }
            final int[] temp = prev;
            prev = curr;
            curr = temp;
        }
        return prev[yLength];
    }

    private String fingerprint(final String x, final String y) {
        return xLength + ":" + yLength + ":" + rollingHash(x) + ":" + rollingHash(y) + ":" + x.charAt(0) + ":" + y.charAt(0);
    }

    private long rollingHash(final String str) {
        long h = 0;
        for (int i = 0; i < str.length(); i++) {
            h = (h * 131 + str.charAt(i)) % 1_000_000_007L;
        }
        return h;
    }

    private void ensureMatrixInitialized() {
        if (s != null) {
            return;
        }
        s = new int[xLength + 1][yLength + 1];
        for (int i = 1; i <= xLength; i++) {
            s[i][0] = getScore(1, 0) * i;
        }
        for (int j = 1; j <= yLength; j++) {
            s[0][j] = getScore(0, 1) * j;
        }
        s[0][0] = 0;
    }

    private void computeTile(final int tileRow, final int tileCol, final int[] xMap, final int[] yMap) {
        final int iStart = tileRow * TILE + 1;
        final int iEnd = Math.min(xLength, iStart + TILE - 1);
        final int jStart = tileCol * TILE + 1;
        final int jEnd = Math.min(yLength, jStart + TILE - 1);

        for (int i = iStart; i <= iEnd; i++) {
            final int xi = xMap[i];
            for (int j = jStart; j <= jEnd; j++) {
                final int yj = yMap[j];
                final int diagScore = s[i - 1][j - 1] + getScore(xi, yj);
                final int topColScore = s[i - 1][j] + getScore(xi, 0);
                final int leftRowScore = s[i][j - 1] + getScore(0, yj);
                s[i][j] = Math.max(diagScore, Math.max(leftRowScore, topColScore));
            }
        }
    }
